import { createClient } from '@supabase/supabase-js';

const SUPABASE_URL = process.env.REACT_APP_SUPABASE_URL || 'https://qanhkvpmmhyxafatpgls.supabase.co';
const SUPABASE_ANON_KEY = process.env.REACT_APP_SUPABASE_ANON_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFhbmhrdnBtbWh5eGFmYXRwZ2xzIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODAwNDIwNTksImV4cCI6MjA5NTYxODA1OX0.kPpFhjq6XEfFjxB6BNIojSxT7UUBQKgfjKqn48cXI4M';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

// ─── Auth ─────────────────────────────────────────────────────────────────────
export const signUp = async (email, password, fullName) => {
  const { data, error } = await supabase.auth.signUp({
    email, password,
    options: { data: { full_name: fullName } }
  });
  return { data, error };
};

export const signIn = async (email, password) => {
  const { data, error } = await supabase.auth.signInWithPassword({ email, password });
  return { data, error };
};

export const signOut = async () => {
  const { error } = await supabase.auth.signOut();
  return { error };
};

export const getSession = async () => {
  const { data, error } = await supabase.auth.getSession();
  return { data, error };
};

// ─── Menu ────────────────────────────────────────────────────────────────────
export const getMenuItems = async () => {
  const { data, error } = await supabase
    .from('menu_items').select('*').eq('available', true).order('category');
  return { data, error };
};

export const getAllMenuItems = async () => {
  const { data, error } = await supabase
    .from('menu_items').select('*').order('category');
  return { data, error };
};

export const createMenuItem = async (item) => {
  const { data, error } = await supabase.from('menu_items').insert([item]).select();
  return { data, error };
};

export const updateMenuItem = async (id, updates) => {
  const { data, error } = await supabase.from('menu_items').update(updates).eq('id', id).select();
  return { data, error };
};

export const deleteMenuItem = async (id) => {
  const { error } = await supabase.from('menu_items').delete().eq('id', id);
  return { error };
};

// ─── Reservations ─────────────────────────────────────────────────────────────
export const createReservation = async (reservation) => {
  const { data, error } = await supabase.from('reservations').insert([reservation]).select();
  return { data, error };
};

export const getAllReservations = async () => {
  const { data, error } = await supabase
    .from('reservations').select('*').order('created_at', { ascending: false });
  return { data, error };
};

export const updateReservationStatus = async (id, status) => {
  const { data, error } = await supabase.from('reservations').update({ status }).eq('id', id).select();
  return { data, error };
};

export const deleteReservation = async (id) => {
  const { error } = await supabase.from('reservations').delete().eq('id', id);
  return { error };
};

// ─── Orders ───────────────────────────────────────────────────────────────────
export const createOrder = async (order) => {
  const { data, error } = await supabase.from('orders').insert([order]).select();
  return { data, error };
};

export const createOrderItems = async (items) => {
  const { data, error } = await supabase.from('order_items').insert(items).select();
  return { data, error };
};

export const getAllOrders = async () => {
  const { data, error } = await supabase
    .from('orders').select('*, order_items(*)').order('created_at', { ascending: false });
  return { data, error };
};

export const updateOrderStatus = async (id, status) => {
  const { data, error } = await supabase.from('orders').update({ status }).eq('id', id).select();
  return { data, error };
};

// ─── Reviews ──────────────────────────────────────────────────────────────────
export const getReviews = async () => {
  const { data, error } = await supabase
    .from('reviews').select('*').eq('approved', true).order('created_at', { ascending: false });
  return { data, error };
};

export const getAllReviews = async () => {
  const { data, error } = await supabase
    .from('reviews').select('*').order('created_at', { ascending: false });
  return { data, error };
};

export const createReview = async (review) => {
  const { data, error } = await supabase.from('reviews').insert([review]).select();
  return { data, error };
};

export const updateReviewApproval = async (id, approved) => {
  const { data, error } = await supabase.from('reviews').update({ approved }).eq('id', id).select();
  return { data, error };
};

export const deleteReview = async (id) => {
  const { error } = await supabase.from('reviews').delete().eq('id', id);
  return { error };
};

// ─── Gallery ──────────────────────────────────────────────────────────────────
export const getGalleryImages = async () => {
  const { data, error } = await supabase.from('gallery').select('*').order('sort_order');
  return { data, error };
};

export const createGalleryImage = async (image) => {
  const { data, error } = await supabase.from('gallery').insert([image]).select();
  return { data, error };
};

export const deleteGalleryImage = async (id) => {
  const { error } = await supabase.from('gallery').delete().eq('id', id);
  return { error };
};

// ─── Stats for dashboard ──────────────────────────────────────────────────────
export const getDashboardStats = async () => {
  const [orders, reservations, reviews, menuItems] = await Promise.all([
    supabase.from('orders').select('id, total_amount, created_at, status'),
    supabase.from('reservations').select('id, status, created_at'),
    supabase.from('reviews').select('id, approved'),
    supabase.from('menu_items').select('id, available'),
  ]);
  return {
    orders: orders.data || [],
    reservations: reservations.data || [],
    reviews: reviews.data || [],
    menuItems: menuItems.data || [],
  };
};
